document.addEventListener('DOMContentLoaded', () => {

    // 1. Gallery Construction logic (Asymmetric columns)
    const galleryContainer = document.getElementById('gallery-container');
    
    if (galleryContainer) {
        galleryContainer.innerHTML = '';
        
        // Create 3 columns
        const colCount = 3;
        const columns = [];
        for (let i = 0; i < colCount; i++) {
            const col = document.createElement('div');
            col.className = 'gallery-col';
            columns.push(col);
            galleryContainer.appendChild(col);
        }

        const items = [];

        exactImageSequence.forEach((imgSrc, index) => {
            const item = document.createElement('div');
            item.className = 'gallery-item';
            
            const parallaxWrap = document.createElement('div');
            parallaxWrap.className = 'img-parallax-wrap';

            const img = document.createElement('img');
            img.src = "images/" + imgSrc;
            img.loading = "lazy";
            img.alt = "Portfolio artwork";
            
            parallaxWrap.appendChild(img);
            item.appendChild(parallaxWrap);
            
            // Distribute items sequentially across the 3 columns
            columns[index % colCount].appendChild(item);
            items.push({ element: item, img: img });
        });

        // 2. Reveal Elements on Scroll
        const revealObserver = new IntersectionObserver((entries, observer) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                    observer.unobserve(entry.target);
                }
            });
        }, { root: null, rootMargin: '0px', threshold: 0.05 });

        items.forEach((itemObj, index) => {
            const delay = (Math.floor(index / colCount) % 5) * 100;
            itemObj.element.style.transitionDelay = `${delay}ms`;
            revealObserver.observe(itemObj.element);
        });

        // 3. Premium Window Parallax System
        let lastScrollY = window.scrollY;
        let ticking = false;

        const updateParallax = () => {
            const scrollY = window.scrollY;
            const windowHeight = window.innerHeight;

            items.forEach((itemObj) => {
                const rect = itemObj.element.getBoundingClientRect();
                
                // Only process items currently in or near viewport
                if (rect.top < windowHeight + 200 && rect.bottom > -200) {
                    const elementCenterY = rect.top + (rect.height / 2);
                    const viewportCenterY = windowHeight / 2;
                    const distanceFromCenter = elementCenterY - viewportCenterY;
                    
                    // Inner parallax speed (subtle window effect)
                    const parallaxSpeed = 0.15;
                    const yTranslate = distanceFromCenter * parallaxSpeed;

                    itemObj.img.style.transform = `scale(1.2) translateY(${yTranslate}px)`;
                }
            });

            ticking = false;
        };

        window.addEventListener('scroll', () => {
            if (!ticking) {
                window.requestAnimationFrame(updateParallax);
                ticking = true;
            }
        });
        
        // Initial setup
        updateParallax();
    }

    // 3. Smooth Scrolling for nav links
    document.querySelectorAll('.nav-link, .nav-btn, .cta-button').forEach(anchor => {
        anchor.addEventListener('click', function (e) {
            const href = this.getAttribute('href');
            if (href.startsWith('#')) {
                e.preventDefault();
                const target = document.querySelector(href);
                if (target) {
                    target.scrollIntoView({
                        behavior: 'smooth'
                    });
                }
            }
        });
    });
    // 4. Modal Logic
    const ctaBtn = document.getElementById('floating-cta');
    const modal = document.getElementById('contact-modal');
    const closeBtn = document.getElementById('close-modal');
    const form = document.getElementById('contact-form');
    const successMsg = document.getElementById('success-msg');

    if (ctaBtn && modal && closeBtn) {
        ctaBtn.addEventListener('click', () => modal.classList.add('active'));
        closeBtn.addEventListener('click', () => modal.classList.remove('active'));
        modal.addEventListener('click', (e) => {
            if (e.target === modal) modal.classList.remove('active');
        });
    }

    if (form) {
        form.addEventListener('submit', (e) => {
            e.preventDefault();
            form.style.display = 'none';
            successMsg.style.display = 'block';
            setTimeout(() => {
                modal.classList.remove('active');
                setTimeout(() => {
                    form.reset();
                    form.style.display = 'flex';
                    successMsg.style.display = 'none';
                }, 400);
            }, 2500);
        });
    }
});
